function generateResults(year, make, model, part) {
  if (!year||!make||!model||!part) return [];
  const base = part.toLowerCase().includes("engine")?1200:part.toLowerCase().includes("transmission")?900:part.toLowerCase().includes("turbo")?650:part.toLowerCase().includes("alternator")||part.toLowerCase().includes("starter")?150:part.toLowerCase().includes("radiator")?280:400;
  return [
    {id:1,yard:YARDS[0],price:base,miles:32000,condition:"Excellent",warranty:"6 Months",shipping:5,inStock:true},
    {id:2,yard:YARDS[1],price:Math.round(base*.88),miles:78000,condition:"Good",warranty:"90 Days",shipping:7,inStock:true},
    {id:3,yard:YARDS[2],price:Math.round(base*.95),miles:51000,condition:"Very Good",warranty:"6 Months",shipping:8,inStock:true},
    {id:4,yard:YARDS[3],price:Math.round(base*1.1),miles:94000,condition:"Good",warranty:"30 Days",shipping:10,inStock:false},
  ];
}

