// Populate search form selects
function initSearchForm(formId, opts={}) {
  const form = document.getElementById(formId);
  if (!form) return;

  const yearSel = form.querySelector('[name=year]');
  const makeSel = form.querySelector('[name=make]');
  const modelSel = form.querySelector('[name=model]');
  const partSel = form.querySelector('[name=part]');

  if (yearSel) YEARS.forEach(y => { const o=document.createElement('option'); o.value=o.textContent=y; yearSel.appendChild(o); });
  if (makeSel) CAR_MAKES.forEach(m => { const o=document.createElement('option'); o.value=o.textContent=m; makeSel.appendChild(o); });
  if (partSel) {
    PART_CATEGORIES.forEach(cat => {
      const og = document.createElement('optgroup');
      og.label = cat.label;
      cat.parts.forEach(p => { const o=document.createElement('option'); o.value=o.textContent=p; og.appendChild(o); });
      partSel.appendChild(og);
    });
  }
  if (makeSel && modelSel) {
    makeSel.addEventListener('change', () => {
      modelSel.innerHTML = '<option value="">Select Model</option>';
      modelSel.disabled = !makeSel.value;
      if (makeSel.value) {
        (CAR_MODELS[makeSel.value]||[]).forEach(m => { const o=document.createElement('option'); o.value=o.textContent=m; modelSel.appendChild(o); });
      }
      if (partSel) { partSel.disabled = true; }
    });
    if (modelSel && partSel) {
      modelSel.addEventListener('change', () => { partSel.disabled = !modelSel.value; });
    }
  }

  // Pre-fill from opts or URL params
  const sp = new URLSearchParams(window.location.search);
  if (yearSel && (opts.year||sp.get('year'))) yearSel.value = opts.year||sp.get('year');
  if (makeSel && (opts.make||sp.get('make'))) {
    makeSel.value = opts.make||sp.get('make');
    makeSel.dispatchEvent(new Event('change'));
    setTimeout(()=>{
      if (modelSel && (opts.model||sp.get('model'))) { modelSel.value=opts.model||sp.get('model'); modelSel.dispatchEvent(new Event('change')); }
      setTimeout(()=>{ if (partSel && (opts.part||sp.get('part'))) partSel.value=opts.part||sp.get('part'); },50);
    },50);
  }

  form.addEventListener('submit', e => {
    e.preventDefault();
    const y=yearSel?.value,ma=makeSel?.value,mo=modelSel?.value,p=partSel?.value;
    if (!y||!ma||!mo||!p) return;
    window.location.href=`search.html?year=${encodeURIComponent(y)}&make=${encodeURIComponent(ma)}&model=${encodeURIComponent(mo)}&part=${encodeURIComponent(p)}`;
  });
}

function starsHTML(n) {
  return Array.from({length:5},(_,i)=>`<span class="star">${i<n?'★':'☆'}</span>`).join('');
}
